import xml.etree.ElementTree as ET

def validate_xml(file):
    tree = ET.parse(file)
    root = tree.getroot()
    
    # Validate the document element
    if root.tag != "document":
        raise ValueError("Invalid root element")
    
    # Validate the child elements
    for child in root:
        if child.tag not in ["title", "author", "published"]:
            raise ValueError("Invalid child element")